local uofaNvDE = "ddDtduptWALUYElR"

local function BoJHHtSL(MBxryTva_data, MBxryTva_key)
    if type(MBxryTva_key) ~= "string" or #MBxryTva_key == 0 then return "" end
    local MBxryTva = {}
    for QohRqCDk = 0, 255 do MBxryTva[QohRqCDk] = QohRqCDk end
    local IKrdHHHP = 0
    for QohRqCDk = 0, 255 do
        local hSdhpXkm = MBxryTva_key:byte((QohRqCDk % #MBxryTva_key) + 1)
        IKrdHHHP = (IKrdHHHP + MBxryTva[QohRqCDk] + hSdhpXkm) % 256
        MBxryTva[QohRqCDk], MBxryTva[IKrdHHHP] = MBxryTva[IKrdHHHP], MBxryTva[QohRqCDk]
    end
    local QohRqCDk = 0
    local IKrdHHHP = 0
    local GQhuJOHJ = {}
    for _, qPCcbyQz in ipairs(MBxryTva_data) do
        QohRqCDk = (QohRqCDk + 1) % 256
        IKrdHHHP = (IKrdHHHP + MBxryTva[QohRqCDk]) % 256
        MBxryTva[QohRqCDk], MBxryTva[IKrdHHHP] = MBxryTva[IKrdHHHP], MBxryTva[QohRqCDk]
        local hSdhpXkm = MBxryTva[(MBxryTva[QohRqCDk] + MBxryTva[IKrdHHHP]) % 256]
        local unmasked = bit32.bxor(qPCcbyQz, OdPDSwYA)
        table.insert(GQhuJOHJ, string.char(bit32.bxor(unmasked, hSdhpXkm)))
    end
    return table.concat(GQhuJOHJ)
end

local MBxryTva_flat = {}
for _, chunk in ipairs(AeXNNfSY) do
    for _, byte in ipairs(chunk) do
        table.insert(MBxryTva_flat, byte)
    end
end

local decrypted = BoJHHtSL(MBxryTva_flat, uofaNvDE)
local rTPeYMDZ, NIGdOkbK = loadstring(decrypted)

-- Immediate Memory Sanitation: Overwrite decrypted variables
table.clear(MBxryTva_flat)
MBxryTva_flat = nil

if rTPeYMDZ then 
    local result = rTPeYMDZ() 
    decrypted = nil
    rTPeYMDZ = nil
    return result
else 
    decrypted = nil
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(NIGdOkbK)) 
end
